/**
 * k-way merge of pre-sorted (descending score) arrays.
 * Uses a simple priority-queue simulation; replace with a proper
 * heap library (e.g. @datastructures-js/priority-queue) for large k.
 *
 * @param {Array<Array<{id:string, score:number, text:string}>>} streams
 * @param {number} limit  maximum items to return
 * @returns {Array<{id:string, score:number, text:string}>}
 */
function kWayMerge(streams, limit) {
  // Pointers into each stream
  const ptrs = streams.map(() => 0);
  const result = [];
  const seen = new Set();

  while (result.length < limit) {
    // Find stream with the highest current element
    let bestScore = -Infinity;
    let bestStream = -1;

    for (let i = 0; i < streams.length; i++) {
      const idx = ptrs[i];
      if (idx < streams[i].length && streams[i][idx].score > bestScore) {
        bestScore = streams[i][idx].score;
        bestStream = i;
      }
    }

    if (bestStream === -1) break;  // all streams exhausted

    const item = streams[bestStream][ptrs[bestStream]];
    ptrs[bestStream]++;

    if (seen.has(item.id)) continue;   // deduplicate inline
    seen.add(item.id);
    result.push(item);
  }

  return result;
}

// Demo
const streamA = [{ id: "d1", score: 0.95, text: "alpha" },
                 { id: "d3", score: 0.72, text: "gamma" }];
const streamB = [{ id: "d2", score: 0.88, text: "beta"  },
                 { id: "d1", score: 0.85, text: "alpha" }];  // duplicate d1
const streamC = [{ id: "d4", score: 0.80, text: "delta" }];

const merged = kWayMerge([streamA, streamB, streamC], 4);
console.log(merged.map(x => `${x.id}(${x.score})`).join(", "));
// d1(0.95), d2(0.88), d4(0.80), d3(0.72)

# Wrong — infinite recursion on any cycle
def dfs_bad(node, graph):
    for nb in graph[node]:
        dfs_bad(nb, graph)

# Right — track visited nodes
def dfs_safe(node, graph, visited=None):
    if visited is None:
        visited = set()
    if node in visited:
        return
    visited.add(node)
    for nb in graph.get(node, []):
        dfs_safe(nb, graph, visited)
